1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string };
14	type QuoteStep = { op: "quote"; items: Item[] };
15	type Input = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
16	type QuoteResult = { premium: number };
17	
18	const itemPremium = (item: Item): number => {
19	  const base = BASE_PREMIUM[item.type];
20	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
21	  return base + firstInsuranceSurcharge;
22	};
23	
24	const sumItemPremiums = (items: Item[]): number =>
25	  items.reduce((sum, item) => sum + itemPremium(item), 0);
26	
27	// MHPCO always rounds premiums in its own favor (up).
28	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
29	
30	const quotePremium = (step: QuoteStep): QuoteResult => ({
31	  premium: roundUpInMHPCOFavor(sumItemPremiums(step.items) + PROCESSING_FEE),
32	});
33	
34	export const run = (input: Input): { results: QuoteResult[] } => ({
35	  results: input.steps.map(quotePremium),
36	});
37

